function escapeHTML(str){
    return str
        .replace(/&/g,"&amp;")
        .replace(/</g,"&lt;")
        .replace(/>/g,"&gt;")
        .replace(/"/g,"&quot;")
        .replace(/'/g,"&#39;");
}
function renderColorText(text) {
  return text.replace(
    /@\{(#[0-9a-fA-F]{6})\}([\s\S]*?)@/g,
    '<p style="color:$1;">$2</p>'
  );
}
function renderVideoShortcut(text) {
  const regex = /@\[(.*?)\]\((.*?)\)/g;
  return text.replace(regex, (match, title, url, offset, str) => {
	if (offset > 0 && str[offset - 1] === "`") {
      return match;
    }
    url = url.trim();
    if (!/^https?:\/\//i.test(url)) {
      return match;
    }
    return `<video src="${encodeURI(url)}" controls title="${escapeHTML(title)}"></video>`;
  });
}
const renderer = {
  code({ text, lang }) {
    const langClass = lang ? ` class="language-${lang}"` : '';
    let htm = text.replace(/br&gt;/gi,"br&shy;&gt;");
	htm = htm.replace(/@@@@/gi,"@&shy;@@&shy;@");
	htm = htm.replace(/@\{#/gi,"@\{&shy;#");
	return `<pre><code${langClass}>${htm}</code></pre>`;
  },
  codespan({ text }) {
	let htm = text.replace(/br&gt;/gi,"br&shy;&gt;");
	htm = htm.replace(/@@@@/gi,"@&shy;@@&shy;@");
	htm = htm.replace(/@\{#/gi,"@\{&shy;#");
    return `<code>${htm}</code>`;
  },
   link({ href, title, tokens }) {
	if (href.startsWith("https://meta.stalltrix.com/")||href.startsWith("https://www.kepdb.com/")){
	const u = new URL(href);
	if ((u.pathname=="/index.php" && u.search.startsWith("?topic=")) || u.pathname.startsWith("/t/topic/")){href=u.pathname+u.search+u.hash;}
	}
	if ((/^https?:\/\//i.test(href)) || (href.startsWith("/index.php?topic=")&&(!href.includes("&"))&&(!href.includes("%"))) || href.startsWith("/t/topic/")) {
    const text = this.parser.parseInline(tokens);
    if (href[0]==='/' && href[1]!=='/'){
	return `<a href="${href}" rel="noopener"${
      title ? ` title="${escapeHTML(title)}"` : ""
    }>${text}</a>`;
	}
	return `<a href="${href}" target="_blank" rel="noopener noreferrer nofollow"${
      title ? ` title="${escapeHTML(title)}"` : ""
    }>${text}</a>`;
	}
    return this.parser.parseInline(tokens);
  },
  image({ href, title, text }) {
    if (!/^https?:\/\//i.test(href)) {
      return '!{Image Broken}';
    }
    if (text) {
     const parts = text.split("|");
     if (parts.length === 2) {
      const name = parts[0];
      const [width, height] = parts[1].split("x").map(Number);

      if (!Number.isNaN(width) && !Number.isNaN(height)) {
		   if (width>0 && height>0 && width<5000 && height<5000) {
                return `<img src="${href}" width="${width}" height="${height}" alt="${escapeHTML(name)}"${
          title ? ` title="${escapeHTML(title)}"` : ""
        }>`;
		   }
      }
     }
    }
    return `<img src="${href}" alt="${escapeHTML(text)}"${
      title ? ` title="${escapeHTML(title)}"` : ""
    }>`;
  },
  html({ text }) {
  if (text.startsWith('<video')) {
    return text;
  }
    return '';
  }
};
marked.use({ renderer });
function resolvMarkdown(input){
	let preText = escapeHTML(input);
	preText = renderVideoShortcut(preText);
    preText = preText.replace(/\n&gt; /gi,"\n> ")
	if (preText.startsWith("&gt; ")) {preText = "> " + preText.slice(5);}
    let html = marked.parse(preText);
    html = html
        .replace(/&lt;br&gt;/gi,"<br>")
        .replace(/&lt;br\/&gt;/gi,"<br>");
	html = html.replace(/@@@@/gi,"&nbsp;&nbsp;&nbsp;&nbsp;");
	html = renderColorText(html);
	html = html.replace(/src=\"j/gi,"src=\"g").replace(/src=\"d/gi,"src=\"g").replace(/src=\"f/gi,"src=\"g");
	return html;
}